    /**
     * When the session was created (Unix timestamp in seconds)
     */
    public var createdAt: UInt64
    /**
     * When the session expires (Unix timestamp in seconds)
     */
    public var expiresAt: UInt64
    /**
     * Optional description of the session
     */
