// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * Broadcast mode for transactions
 */

public enum BroadcastMode: Equatable, Hashable {
    
    /**
     * Synchronous - returns after CheckTx
     */
    case sync
    /**
     * Asynchronous - returns immediately
     */
    case async
    /**
     * Block - waits until transaction is included in a block
     */
    case block



}

#if compiler(>=6)
extension BroadcastMode: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeBroadcastMode: FfiConverterRustBuffer {
    typealias SwiftType = BroadcastMode

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> BroadcastMode {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .sync
        
        case 2: return .async
        
        case 3: return .block
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: BroadcastMode, into buf: inout [UInt8]) {
        switch value {
        
        
        case .sync:
            writeInt(&buf, Int32(1))
        
        
        case .async:
            writeInt(&buf, Int32(2))
        
        
        case .block:
            writeInt(&buf, Int32(3))
        
        }
    }
}


