/**
 * Main error type for the mob library
 */
public enum MobError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    /**
     * RPC-related errors
     */
    case Rpc(message: String)
    
    /**
     * Transaction-related errors
     */
    case Transaction(message: String)
    
    /**
     * Signing-related errors
     */
    case Signing(message: String)
    
    /**
     * Key derivation errors
     */
    case KeyDerivation(message: String)
    
    /**
     * Address parsing/generation errors
     */
    case Address(message: String)
    
    /**
     * Serialization/deserialization errors
     */
    case Serialization(message: String)
    
    /**
     * Invalid input errors
     */
    case InvalidInput(message: String)
    
    /**
     * Account-related errors
     */
    case Account(message: String)
    
    /**
     * Network-related errors
     */
    case Network(message: String)
    
    /**
     * Gas estimation errors
     */
    case GasEstimation(message: String)
    
    /**
     * Insufficient funds
     */
    case InsufficientFunds(message: String)
    
    /**
     * Timeout errors
     */
    case Timeout(message: String)
    
    /**
     * Session expired errors
     */
    case SessionExpired(message: String)
    
    /**
     * Generic error
     */
    case Generic(message: String)
    

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

